select:
SELECT Volun_Act_No AS volunActNo, Volun_Act_Title AS volunActTitle, Volun_Act_Recru_Begin AS volunActRecruBegin, Volun_Act_Recru_End AS volunActRecruEnd, Volun_Act_Proc_Begin AS volunActProcBegin, Volun_Act_Proc_End AS volunActProcEnd, Volun_Act_Point AS volunActPoint, Volun_Act_Act_Type AS volunActActType, Volun_Act_Age_Group AS volunActAgeGroup, Volun_Act_Address AS volunActAddress FROM TBL_VOLUN_ACTIVITY
Volun_Act_Recru_End >= SYSDATE
AND Volun_Act_Act_Type = #{actType}
AND Volun_Act_Age_Group = #{ageGroup}
AND Volun_Act_Recru_End >= SYSDATE
AND Volun_Act_Recru_End < SYSDATE
AND Volun_Act_Proc_Begin <= #{volunDate} AND Volun_Act_Proc_End >= #{volunDate}
AND Volun_Act_Title LIKE '%' || #{keyword} || '%'
AND Volun_Act_Point = #{keyword}
ORDER BY Volun_Act_No DESC
